<span class="line"><span style="color:#ABB2BF;">            .</span><span style="color:#61AFEF;">OnCollection</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;outfit&quot;</span><span style="color:#ABB2BF;">)</span></span>
